const now = new Date();
const today = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const timeStr = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Chicago' });
const dayOfWeek = now.toLocaleDateString('en-US', { weekday: 'long', timeZone: 'America/Chicago' });
return [{ json: { today, timeStr, dayOfWeek, updatedAt: `${dayOfWeek}, ${today} at ${timeStr} CT` } }];

const { today, timeStr, dayOfWeek, updatedAt } = $('Set Time').first().json;

let mtl = '';
try {
  const bin = $('S3: Read MTL').first().binary?.data;
  if (bin) mtl = Buffer.from(bin.data, 'base64').toString('utf-8');
} catch(e) {}

const areaEmoji = { faith:'🙏', family:'👨‍👩‍👧', business:'🚀', consulting:'💼', work:'🏥', health:'💪', home:'🏠', personal:'🎯' };
const AREAS = ['faith','family','business','consulting','work','health','home','personal'];

// Parse all open tasks
const allTasks = [];
const re = /^- \[ \] (.+?)\[area:: (\w+)\].*?\[priority:: ([ABC])\](?:.*?\[due:: (\d{4}-\d{2}-\d{2})\])?/gm;
let m;
while ((m = re.exec(mtl)) !== null) {
  allTasks.push({ task: m[1].trim(), area: m[2], priority: m[3], due: m[4] || null });
}

const overdue   = allTasks.filter(t => t.due && t.due < today);
const dueToday  = allTasks.filter(t => t.due === today);
const upcoming  = allTasks.filter(t => t.due && t.due > today).slice(0, 10);
const noDue     = allTasks.filter(t => !t.due);

const byArea = {};
for (const area of AREAS) byArea[area] = allTasks.filter(t => t.area === area).length;

const priorityCounts = { A: allTasks.filter(t=>t.priority==='A').length, B: allTasks.filter(t=>t.priority==='B').length, C: allTasks.filter(t=>t.priority==='C').length };

// Build Obsidian Markdown dashboard
const pct = (n, total) => total > 0 ? Math.round(n/total*100) : 0;

let md = `---\ntype: live-dashboard\nupdated: ${today}T${timeStr}\n---\n\n`;
md += `# 🧠 Life OS Dashboard\n\n> 🔄 **Last updated:** ${updatedAt}\n\n`;

// Summary stats
md += `## 📈 Task Overview\n\n`;
md += `| Metric | Count |\n|---|---|\n`;
md += `| 🔥 Overdue | **${overdue.length}** |\n`;
md += `| 📅 Due Today | **${dueToday.length}** |\n`;
md += `| 📆 Upcoming | ${upcoming.length} |\n`;
md += `| ❓ No Due Date | ${noDue.length} |\n`;
md += `| 📋 Total Open | ${allTasks.length} |\n`;
md += `| 🔴 Priority A | ${priorityCounts.A} | \n`;
md += `| 🟡 Priority B | ${priorityCounts.B} |\n`;
md += `| ⚪ Priority C | ${priorityCounts.C} |\n\n`;

// Area breakdown
md += `## 🗂️ By Life Area\n\n`;
for (const area of AREAS) {
  const count = byArea[area] || 0;
  const bar = '█'.repeat(Math.min(count, 20)) + '░'.repeat(Math.max(0, 10-Math.min(count,10)));
  md += `| ${areaEmoji[area] || '📌'} ${area.charAt(0).toUpperCase()+area.slice(1)} | ${count} tasks | \`${bar}\` |\n`;
}
md += '\n';

// Overdue section
if (overdue.length > 0) {
  md += `## 🔥 Overdue (${overdue.length})\n\n`;
  overdue.sort((a,b) => a.priority < b.priority ? -1 : 1).slice(0, 15).forEach(t => {
    const days = Math.floor((new Date(today) - new Date(t.due)) / 86400000);
    md += `- [ ] ${t.task} [area:: ${t.area}] [priority:: ${t.priority}] [due:: ${t.due}] ⚠️ ${days}d overdue\n`;
  });
  md += '\n';
}

// Due today
if (dueToday.length > 0) {
  md += `## 📅 Due Today (${dueToday.length})\n\n`;
  dueToday.sort((a,b) => a.priority < b.priority ? -1 : 1).forEach(t => {
    md += `- [ ] ${t.task} [area:: ${t.area}] [priority:: ${t.priority}]\n`;
  });
  md += '\n';
}

// Q2 Rocks
md += `## 🎯 Q2 2026 Rocks\n\n`;
md += `- [ ] 🙏 Faith: Launch social media Bible study (4 sessions)\n`;
md += `- [ ] 👨‍👩‍👧 Family: Marriage Alignment Questionnaire + bi-weekly check-in\n`;
md += `- [ ] 🚀 Business: Ship MVP — website live, offer defined, 3 outreach convos\n`;
md += `- [ ] 🏥 Work: Deliver Union project\n`;
md += `- [ ] 💪 Health: Hip decision + 3x/week gym for 8 weeks\n\n`;

md += `---\n*Auto-refreshed hourly by ObsidianHomeOrchestrator | ${allTasks.length} open tasks across ${AREAS.length} areas*\n`;

const buf = Buffer.from(md, 'utf-8');
return [{ json: {
  key: '000_Master Dashboard/Live Dashboard.md',
  today, updatedAt,
  totalTasks: allTasks.length,
  overdueCount: overdue.length
}, binary: { data: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: 'Live Dashboard.md', fileExtension: 'md', fileSize: buf.length } } }];
